/**
 * Modes supported by the [ShadowCastAnalysis](https://developers.arcgis.com/javascript/latest/references/core/analysis/ShadowCastAnalysis/).
 *
 * @since 5.0
 */
export type ShadowCastMode = "discrete" | "min-duration" | "total-duration";

/**
 * Modes supported by the [ShadowCastAnalysis](https://developers.arcgis.com/javascript/latest/references/core/analysis/ShadowCastAnalysis/) when using the "total-duration" mode.
 *
 * @since 5.0
 */
export type ShadowCastTotalDurationMode = "continuous" | "hourly";